"""
Parameterized generator for GH161_mitmproxy_8112.

Source PR:    https://github.com/mitmproxy/mitmproxy/pull/8112
Source Issue: N/A

Seed varies: renames 'action' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH161_mitmproxy_8112'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH161_mitmproxy_8112'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('action', 'action' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH161_mitmproxy_8112',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'mitmproxy/mitmproxy',
                "pr_number": 8112,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/mitmproxy/mitmproxy/pull/8112",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            '.github/workflows/autofix.yml': 'name: autofix.ci\n\non:\n  pull_request:\n  push:\n    branches:\n      - main\n\npermissions:\n  contents: read\n\njobs:\n  autofix:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: mhils/workflows/checkout@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: mhils/workflows/setup-uv@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n\n      # If we need to update the lockfile (--check returns an error),\n      # make sure to upgrade everything.\n      - run: uv lock --check || uv lock --upgrade\n\n      - uses: mhils/workflows/uv-sync@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n\n      - run: ruff check --fix-only .\n      - run: ruff format .\n\n      - run: web/gen/all\n\n      - uses: actions/setup-node@v6\n        with:\n          node-version-file: .github/node-version.txt\n      - run: npm ci\n        working-directory: web\n      - run: npm run eslint\n        working-directory: web\n        continue-on-error: true\n      - run: npm run prettier\n        working-directory: web\n\n      - uses: mhils/add-pr-ref-in-changelog@main\n\n      - uses: autofix-ci/action@635ffb0c9798bd160680f18fd73371e355b85f27\n',
            '.github/workflows/main.yml': 'name: CI\n\non:\n  push:\n    branches:\n      - \'**\'\n      - \'!dependabot/**\'\n      - \'!*-patch-*\'\n  pull_request:\n  merge_group:\n  workflow_dispatch:\n\npermissions:\n  contents: read\n\nconcurrency:\n  group: ${{ github.workflow }}-${{ github.ref }}\n  cancel-in-progress: true\n\njobs:\n  tox:\n    strategy:\n      fail-fast: false\n      matrix:\n        env: [lint, filename_matching, mypy, individual_coverage, old-dependencies, test-offline]\n    name: ${{ matrix.env }}\n    runs-on: ubuntu-latest\n    steps:\n      - uses: mhils/workflows/checkout@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: mhils/workflows/setup-uv@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: mhils/workflows/uv-sync@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n        with:\n          args: --only-group tox\n\n      - run: tox -e ${{ matrix.env }}\n\n  test:\n    strategy:\n      fail-fast: false\n      matrix:\n        include:\n          - os: ubuntu-latest\n            py: "3.14"\n          - os: windows-latest\n            py: "3.14"\n          - os: macos-latest\n            py: "3.14"\n          - os: ubuntu-latest\n            py: "3.13"\n          - os: ubuntu-latest\n            py: "3.12"\n    runs-on: ${{ matrix.os }}\n    steps:\n      - uses: mhils/workflows/checkout@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: mhils/workflows/setup-uv@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: mhils/workflows/uv-sync@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n        with:\n          args: --only-group tox\n\n      - run: tox -e py${{ matrix.py }}\n      - uses: codecov/codecov-action@v5\n        with:\n          token: ${{ secrets.CODECOV_TOKEN }}\n          files: ./coverage.xml\n\n  build:\n    strategy:\n      fail-fast: false\n      matrix:\n        include:\n          - image: macos-15\n            platform: macos-arm64\n          - image: macos-15-intel\n            platform: macos-x86_64\n          - image: windows-2025\n            platform: windows\n          - image: ubuntu-latest\n            platform: linux-x86_64\n            container: debian:11  # Old version so we get oldest glibc possible.\n          - image: ubuntu-24.04-arm\n            platform: linux-arm64\n            container: debian:11  # Old version so we get oldest glibc possible.\n    runs-on: ${{ matrix.image }}\n    container:\n      image: ${{ matrix.container }}\n    steps:\n      - if: matrix.container\n        run: |\n          apt-get update\n          apt-get install --no-install-recommends -y git ca-certificates binutils build-essential\n      - uses: mhils/workflows/checkout@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: mhils/workflows/setup-uv@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: mhils/workflows/uv-sync@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - run: uv pip install .  # pyinstaller 5.9 does not like pyproject.toml + editable installs.\n\n      - if: runner.os == \'macOS\' && github.repository == \'mitmproxy/mitmproxy\'\n            && (startsWith(github.ref, \'refs/heads/\') || startsWith(github.ref, \'refs/tags/\'))\n        id: keychain\n        uses: apple-actions/import-codesign-certs@b610f78488812c1e56b20e6df63ec42d833f2d14\n        with:\n          keychain: ${{ runner.temp }}/temp\n          p12-file-base64: ${{ secrets.APPLE_CERTIFICATE }}\n          p12-password: ${{ secrets.APPLE_CERTIFICATE_PASSWORD }}\n      - if: runner.os == \'macOS\' && github.repository == \'mitmproxy/mitmproxy\'\n            && (startsWith(github.ref, \'refs/heads/\') || startsWith(github.ref, \'refs/tags/\'))\n        run: |\n          python -u release/build.py macos-app \\\n            --keychain "${{ runner.temp }}/temp.keychain" \\\n            --team-id "S8XHQB96PW" \\\n            --apple-id "${{ secrets.APPLE_ID }}" \\\n            --password "${{ secrets.APPLE_APP_PASSWORD }}"\n\n      # Linux\n      - if: runner.os == \'Linux\'\n        run: python -u release/build.py standalone-binaries\n\n      # Windows\n      - if: runner.os == \'Windows\'\n        run: python -u release/build.py standalone-binaries\n\n      - uses: actions/upload-artifact@v6\n        with:\n          name: binaries.${{ matrix.platform }}\n          path: release/dist\n\n  build-wheel:\n    uses: mhils/workflows/.github/workflows/python-build.yml@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n    with:\n      artifact: binaries.wheel\n\n  build-windows-installer:\n    runs-on: windows-latest\n    if: github.repository == \'mitmproxy/mitmproxy\' && (\n        github.ref == \'refs/heads/main\' ||\n        github.ref == \'refs/heads/citest\' ||\n        startsWith(github.ref, \'refs/tags/\')\n      )\n    steps:\n      - uses: mhils/workflows/checkout@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: mhils/workflows/setup-uv@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: mhils/workflows/uv-sync@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - run: uv pip install .  # pyinstaller 5.9 does not like pyproject.toml + editable installs.\n      - run: python -u release/build.py installbuilder-installer msix-installer\n        env:\n          CI_BUILD_KEY: ${{ secrets.CI_BUILD_KEY }}\n\n      - uses: actions/upload-artifact@v6\n        with:\n          name: binaries.windows-installer\n          path: release/dist\n\n  test-web-ui:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: mhils/workflows/checkout@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: actions/setup-node@v6\n        with:\n          node-version-file: .github/node-version.txt\n      - name: Cache Node.js modules\n        uses: actions/cache@v5\n        with:\n          # npm cache files are stored in `~/.npm` on Linux/macOS\n          path: ~/.npm\n          key: ${{ runner.OS }}-node-${{ hashFiles(\'**/package-lock.json\') }}\n          restore-keys: |\n            ${{ runner.OS }}-node-\n            ${{ runner.OS }}-\n      - working-directory: ./web\n        run: npm ci\n      - working-directory: ./web\n        run: npm test\n      - uses: codecov/codecov-action@v5\n        with:\n          token: ${{ secrets.CODECOV_TOKEN }}\n          files: ./web/coverage/coverage-final.json\n\n  test-docker:\n    runs-on: ubuntu-latest\n    needs: build-wheel\n    steps:\n      - uses: mhils/workflows/checkout@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: actions/download-artifact@v7\n        with:\n          name: binaries.wheel\n          path: release/docker\n      - name: Build container\n        run: docker build --tag localtesting release/docker\n      - name: Test container\n        run: docker run --rm -v $PWD/release:/release localtesting mitmdump -s /release/selftest.py\n\n  docs:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: mhils/workflows/checkout@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: mhils/workflows/setup-uv@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: mhils/workflows/uv-sync@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - run: |\n          wget -q https://github.com/gohugoio/hugo/releases/download/v0.139.3/hugo_extended_0.139.3_linux-amd64.deb\n          echo "3e58800d1fee57269208d07d104ae1a6ab886615344099f2dca0c6ad5279bc11 hugo_extended_0.139.3_linux-amd64.deb" | sha256sum -c\n          sudo dpkg -i hugo*.deb\n\n      - run: ./docs/build.py\n      - uses: actions/upload-artifact@v6\n        with:\n          name: docs\n          path: docs/public\n      # For releases, also build the archive version of the docs.\n      - run: ./docs/build.py\n        env:\n          DOCS_ARCHIVE: ${{ github.ref_name }}\n      - if: startsWith(github.ref, \'refs/tags/\')\n        uses: actions/upload-artifact@v6\n        with:\n          name: docs-archive\n          path: docs/public\n\n  check:\n    if: always()\n    needs:\n    - tox\n    - test\n    - test-docker\n    - test-web-ui\n    - build\n    - build-wheel\n    - build-windows-installer\n    - docs\n    uses: mhils/workflows/.github/workflows/alls-green.yml@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n    with:\n      jobs: ${{ toJSON(needs) }}\n      allowed-skips: build-windows-installer\n\n  # Separate from everything else because slow.\n  deploy-docker:\n    if: github.repository == \'mitmproxy/mitmproxy\' && (\n        github.ref == \'refs/heads/main\' ||\n        github.ref == \'refs/heads/citest\' ||\n        startsWith(github.ref, \'refs/tags/\')\n      )\n    permissions:\n      id-token: write\n      attestations: write\n      packages: write\n    environment: deploy-docker\n    needs: check\n    runs-on: ubuntu-latest\n    steps:\n      - uses: mhils/workflows/checkout@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: actions/download-artifact@v7\n        with:\n          name: binaries.wheel\n          path: release/docker\n      - uses: docker/setup-qemu-action@c7c53464625b32c7a7e944ae62b3e17d2b600130 # v3.7.0\n      - uses: docker/setup-buildx-action@8d2750c68a42422c14e847fe6c8ac0403b4cbd6f # v1.6.0\n\n      - name: Login to Docker Hub\n        uses: docker/login-action@c94ce9fb468520275223c153574b00df6fe4bcc9 # v3.7.0\n        with:\n          username: mitmbot\n          password: ${{ secrets.DOCKER_PASSWORD }}\n      - name: Login to GitHub Container Registry\n        uses: docker/login-action@c94ce9fb468520275223c153574b00df6fe4bcc9 # v3.7.0\n        with:\n          registry: ghcr.io\n          username: ${{ github.repository_owner }}\n          password: ${{ secrets.GITHUB_TOKEN }}\n\n      - name: Docker meta\n        id: meta\n        uses: docker/metadata-action@c299e40c65443455700f0fdfc63efafe5b349051\n        env:\n          DOCKER_METADATA_ANNOTATIONS_LEVELS: index\n        with:\n          images: |\n            mitmproxy/mitmproxy\n            ghcr.io/mitmproxy/mitmproxy\n          tags: |\n            type=semver,pattern={{version}}\n            type=semver,pattern={{major}}.{{minor}}\n            type=semver,pattern={{major}}\n            type=raw,value=dev,enable=${{ github.ref == \'refs/heads/main\' }}\n            type=raw,value=citest,enable=${{ github.ref == \'refs/heads/citest\' }}\n\n      - name: Build and push\n        id: push\n        uses: docker/build-push-action@263435318d21b8e681c14492fe198d362a7d2c83 # v6.18.0\n        with:\n          context: release/docker\n          platforms: linux/amd64,linux/arm64\n          push: true\n          provenance: false\n          tags: ${{ steps.meta.outputs.tags }}\n          labels: ${{ steps.meta.outputs.labels }}\n          annotations: ${{ steps.meta.outputs.annotations }}\n      - uses: actions/attest-build-provenance@v3\n        with:\n          subject-name: ghcr.io/${{ github.repository }}\n          subject-digest: ${{ steps.push.outputs.digest }}\n\n  deploy:\n    # This action has access to our AWS keys, so we are extra careful here.\n    # In particular, we don\'t blindly `pip install` anything to minimize the risk of supply chain attacks.\n    if: github.repository == \'mitmproxy/mitmproxy\' && (startsWith(github.ref, \'refs/heads/\') || startsWith(github.ref, \'refs/tags/\'))\n    environment: ${{ (github.ref == \'refs/heads/citest\' || startsWith(github.ref, \'refs/tags/\')) && \'deploy-release\' || \'deploy-snapshot\' }}\n    needs: check\n    runs-on: ubuntu-latest\n    permissions:\n      id-token: write\n      attestations: write\n    env:\n      # PyPI and MSFT keys are only available for the deploy-release environment\n      # The AWS access key for snapshots is scoped to branches/* as well.\n      TWINE_USERNAME: __token__\n      TWINE_PASSWORD: ${{ secrets.TWINE_PASSWORD }}\n      AWS_ACCESS_KEY_ID: ${{ secrets.AWS_ACCESS_KEY_ID }}\n      AWS_SECRET_ACCESS_KEY: ${{ secrets.AWS_SECRET_ACCESS_KEY }}\n      AWS_DEFAULT_REGION: us-west-2\n      MSFT_APP_ID: 9NWNDLQMNZD7\n      MSFT_TENANT_ID: ${{ secrets.MSFT_TENANT_ID }}\n      MSFT_CLIENT_ID: ${{ secrets.MSFT_CLIENT_ID }}\n      MSFT_CLIENT_SECRET: ${{ secrets.MSFT_CLIENT_SECRET }}\n      R2_ACCOUNT_ID: ${{ secrets.R2_ACCOUNT_ID }}\n      R2_ACCESS_KEY_ID: ${{ secrets.R2_ACCESS_KEY_ID }}\n      R2_SECRET_ACCESS_KEY: ${{ secrets.R2_SECRET_ACCESS_KEY }}\n    steps:\n      - uses: mhils/workflows/checkout@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: mhils/workflows/setup-uv@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n      - uses: mhils/workflows/uv-sync@8fe88b311a66c441e01edfebe4cd90d8a47fa335\n        with:\n          args: --only-group deploy\n\n      - uses: actions/download-artifact@v7\n        with:\n          name: docs\n          path: docs/public\n      - if: startsWith(github.ref, \'refs/tags/\')\n        uses: actions/download-artifact@v7\n        with:\n          name: docs-archive\n          path: docs/archive\n      - uses: actions/download-artifact@v7\n        with:\n          pattern: binaries.*\n          merge-multiple: true\n          path: release/dist\n      - id: provenance\n        uses: actions/attest-build-provenance@v3\n        with:\n          subject-path: \'release/dist/*\'\n      - run: |\n          REF=${{ github.ref_name }}\n          mv ${{ steps.provenance.outputs.bundle-path }} release/dist/mitmproxy-${REF#v}.sigstore\n      - run: ls docs/public\n      - run: ls release/dist\n\n      - run: ./release/deploy.py\n\n      - name: Deploy to Microsoft Store (test flight)\n        if: github.ref == \'refs/heads/citest\'\n        run: ./release/deploy-microsoft-store.py release/dist/*.msix\n        env:\n          MSFT_APP_FLIGHT: 174ca570-8cae-4444-9858-c07293f1f13a\n      - name: Deploy to Microsoft Store\n        if: startsWith(github.ref, \'refs/tags/\')\n        run: ./release/deploy-microsoft-store.py release/dist/*.msix\n',
        }
